<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="40" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Let's Get to Know Each Other</p>
      <p slot="message">
        To offer you the best service, please provide us with your (the main applicant's) personal information. It will help us tailor a more presonal customer profile for your
      </p>
      <p slot="message" class="is-size-5 is-size-6-mobile">
        This page inquires about the following form items:
      </p>
      <ul slot="list">
        <li>Your full name and date of birth</li>
        <li>Your email, and phone number</li>
        <li>Your Canadian citizenship and marital statuses</li>
        <li>Your address along with your residence period there and status (rent/own)</li>
      </ul>
    </message-modal>
    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-one-third-desktop">
            <b-field label="Your Full Name" :addons="false" class="info">
              <b-tooltip label="As listed on your birth certificate" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input v-model="fullName" icon="user"></b-input>
            </b-field>
          </div>
          <div class="column is-one-third-desktop">
            <b-field label="Your date of birth" :addons="false" class="info">
              <b-tooltip label="As listed on your birth certificate" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-datepicker placeholder="Click to select" icon="calendar-alt" v-model="dateOfBirth"></b-datepicker>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-one-third-desktop">
            <b-field label="Your marital status" :addons="false" class="info">
              <b-tooltip label="Your marital status at the this time" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-select expanded required v-model="maritalStatus" icon="users" placeholder="I am">
                <option value="Single">Single</option>
                <option value="Married">Married</option>
                <option value="Divorced">Divorced</option>
                <option value="Common Law">Common Law</option>
              </b-select>
            </b-field>
          </div>
          <div class="column is-one-third-desktop">
            <b-field label="Your citizen status" :addons="false" class="info">
              <b-tooltip label="Your current Canadian citizenship status" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-select placeholder="I am" expanded required v-model="citizenship" icon="passport">
                <option value="Canadian Citizen">Canadian citizen</option>
                <option value="Permanent Resident">Permanent Resident</option>
                <option value="Work Visa">Work Visa</option>
                <option value="Non-resident">Non-resident</option>
              </b-select>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-one-third-desktop">
            <b-field label="Your phone number" :addons="false" class="info">
              <b-tooltip label="Your cellular number preffered" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input expanded required v-model="phoneNumber" icon="phone" placeholder="Your cell"></b-input>
            </b-field>
          </div>
          <div class="column is-one-third-desktop">
            <b-field label="Your email" :addons="false" class="info">
              <b-tooltip label="Your personal email preffered" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input expanded required v-model="email" type="email" icon="at" placeholder="Your main email"></b-input>
            </b-field>
          </div>
        </div>

        <address-block :form="$store.state.PersonalForm.address" message="Address of your current residence" icon="home"></address-block>

        <div class="columns is-centered">
          <div class="column is-one-third-desktop">
            <b-field label="Years at this residence" :addons="false" class="info">
              <b-tooltip label="How many years have you lived at this address?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-field>
                <b-input v-model="timeResided" type="text" expanded icon="calendar" placeholder="I've lived here for" v-debounce:600="checkYears"></b-input>
                <span class="control">
                  <div class="is-static button">
                    years
                  </div>
                </span>
              </b-field>
            </b-field>
          </div>
          <div class="column is-one-third-desktop">
            <b-field label="Your residence status" :addons="false" class="info">
              <b-tooltip label="Who does the property belong to?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-select expanded required v-model="residenceStatus" icon="key" placeholder="I am">
                <option value="Own">The owner</option>
                <option value="Rent">I rent</option>
                <option value="Parents">I live with my parents</option>
              </b-select>
            </b-field>
          </div>
        </div>

        <transition name="fadeUp">
          <address-block :form="$store.state.PersonalForm.previousResidence" message="Address of your previous residence" icon="home" v-if="shortResidence"></address-block>
        </transition>

        <transition-group name="fadeUp" mode="out-in">
          <div class="columns is-centered" v-if="shortResidence" key="random_98kd87">
            <div class="column is-one-third-desktop">
              <b-field label="Years at previous residence" :addons="false" class="info">
                <b-tooltip label="How many years have you lived at the previous address?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-field>
                  <b-input v-model="timePreviouslyResided" type="text" expanded icon="calendar" placeholder="I've lived here for"></b-input>
                  <span class="control">
                    <div class="is-static button">
                      years
                    </div>
                  </span>
                </b-field>
              </b-field>
            </div>
            <div class="column is-one-third-desktop">
              <b-field label="Your previous residence status" :addons="false" class="info">
                <b-tooltip label="Did you own or rent your previous property?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-select expanded required v-model="previousResidenceStatus" icon="key" placeholder="I used to">
                  <option value="Own">Own</option>
                  <option value="Rent">Rent</option>
                </b-select>
              </b-field>
            </div>
          </div>
        </transition-group>

        <div class="columns is-centered">
<div class="column is-two-thirds-desktop">
<hr>
          </div>
        </div>

        <to-page back="/property" :next="route" text="Go to Employment Form"></to-page>
      </div>
    </div>
  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
export default {
  data() {
    return {
      page: "Page 3",
      heading: "Your Personal Information",
      toggled: false,
      shortResidence: false
    };
  },
  computed: {
    route() {
      return this.$store.state.StartForm.applicants > 1
        ? "/co-applicant"
        : "/employment";
    },
    dateOfBirth: {
      get() {
        return this.$store.state.PersonalForm.dateOfBirth;
      },
      set(val) {
        this.$store.state.PersonalForm.dateOfBirth = val;
      }
    },
    timePreviouslyResided: {
      get() {
        return this.$store.state.PersonalForm.timePreviouslyResided;
      },
      set(val) {
        this.$store.state.PersonalForm.timePreviouslyResided = val;
      }
    },
    maritalStatus: {
      get() {
        return this.$store.state.PersonalForm.maritalStatus;
      },
      set(val) {
        this.$store.state.PersonalForm.maritalStatus = val;
      }
    },
    citizenship: {
      get() {
        return this.$store.state.PersonalForm.citizenship;
      },
      set(val) {
        this.$store.state.PersonalForm.citizenship = val;
      }
    },
    fullName: {
      get() {
        return this.$store.state.PersonalForm.fullName;
      },
      set(val) {
        this.$store.state.PersonalForm.fullName = val;
      }
    },
    email: {
      get() {
        return this.$store.state.PersonalForm.email;
      },
      set(val) {
        this.$store.state.PersonalForm.email = val;
      }
    },
    phoneNumber: {
      get() {
        return this.$store.state.PersonalForm.phoneNumber;
      },
      set(val) {
        this.$store.state.PersonalForm.phoneNumber = val;
      }
    },
    timeResided: {
      get() {
        return this.$store.state.PersonalForm.timeResided;
      },
      set(val) {
        this.$store.state.PersonalForm.timeResided = val;
      }
    },
    residenceStatus: {
      get() {
        return this.$store.state.PersonalForm.residenceStatus;
      },
      set(val) {
        this.$store.state.PersonalForm.residenceStatus = val;
      }
    },
    previousResidenceStatus: {
      get() {
        return this.$store.state.PersonalForm.previousResidenceStatus;
      },
      set(val) {
        this.$store.state.PersonalForm.previousResidenceStatus = val;
      }
    }
  },
  methods: {
    checkYears(e) {
      (parseFloat(e) < 3) ? this.shortResidence = true : this.shortResidence = false;
    }
  },
  components: {
    addressBlock
  }
};
</script>