<template>
  <b-field label="Asset" :addons="false" class="info">
    <b-tooltip label="Please list all assets in your possession." position="is-left" size="is-medium" type="is-dark" animated multilined v-once>
      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
    </b-tooltip>
    <b-field>
      <b-input v-model="asset.type" type="text" icon="credit-card" style="flex:3;" placeholder="I own"></b-input>
      <b-input v-model="asset.value" icon="dollar-sign" style="flex:2;" placeholder="CAD"></b-input>
      <span class="control">
        <button class="button is-outlined is-primary" v-if="adding" :disabled="fields === 6 || empty" @click="addField">
          <i class="fas fa-plus"></i>&ensp;Add</button>
        <button class="button is-outlined is-danger" v-else @click="removeField">
          <i class="fas fa-minus"></i>&ensp;Remove</button>
      </span>
    </b-field>
  </b-field>
</template>

<script>
export default {
  data() {
    return {
      adding: true,
      asset: {
        type: "",
        value: ""
      }
    };
  },
  methods: {
    addField() {
      if (this.asset.type.length > 2 && this.asset.value.length > 2) {
        this.$emit("addfield");
        this.adding = !this.adding;
        this.$store.dispatch("addAsset", this.asset);
      }
    },
    removeField() {
      this.$emit("removefield");
      this.adding = !this.adding;
      this.$store.dispatch("removeAsset", this.asset.type);
      (this.asset.type = ""), (this.asset.value = "");
    }
  },
  computed: {
    empty() {
      return this.asset.type.length > 2 && this.asset.value.length > 2
        ? false
        : true;
    }
  },
  props: {
    fields: Number
  }
};
</script>