<template>
  <b-field label="Liability" :addons="false" class="info">
    <b-tooltip label="Please list all liabilities that you have incurred." position="is-left" size="is-medium" type="is-dark" animated multilined v-once>
      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
    </b-tooltip>
    <b-field>
      <b-input v-model="liability.type" type="text" icon="credit-card" style="flex:3;" placeholder="I owe"></b-input>
      <b-input v-model="liability.value" icon="dollar-sign" style="flex:2;" placeholder="CAD"></b-input>
      <span class="control">
        <button class="button is-outlined is-primary" v-if="adding" :disabled="fields === 6 || empty" @click="addField">
          <i class="fas fa-plus"></i>&ensp;Add</button>
        <button class="button is-outlined is-danger" v-else @click="removeField">
          <i class="fas fa-minus"></i>&ensp;Remove</button>
      </span>
    </b-field>
  </b-field>
</template>

<script>
export default {
  data() {
    return {
      adding: true,
      liability: {
        type: "",
        value: ""
      }
    };
  },
  methods: {
    addField() {
      if (this.liability.type.length > 2 && this.liability.value.length > 2) {
        this.$emit("addfield");
        this.adding = !this.adding;
        this.$store.dispatch("addLiability", this.liability);
      }
    },
    removeField() {
      this.$emit("removefield");
      this.adding = !this.adding;
      this.$store.dispatch("removeLiability", this.liability.type);
      (this.liability.type = ""), (this.liability.value = "");
    }
  },
  computed: {
    empty() {
      return this.liability.type.length > 2 && this.liability.value.length > 2
        ? false
        : true;
    }
  },
  props: {
    fields: Number
  }
};
</script>
